sql:
SELECT researchers.name, departments.department_name
FROM researchers
INNER JOIN departments ON researchers.department_id = departments.department_id;

SELECT experiments.experiment_id, experiments.experiment_name, experiments.description
FROM experiments
INNER JOIN machine_learning_models ON experiments.experiment_id = machine_learning_models.experiment_id;

SELECT e.experiment_name, df.file_path
FROM experiments e
JOIN data_files df ON e.experiment_id = df.experiment_id;

SELECT DISTINCT researchers.name
FROM researchers
JOIN experiments ON researchers.researcher_id = experiments.researcher_id;

external_knowledge:
- 'explorers' refers to researchers in the 'Exploration' department;
- 'more than a couple of experiments' translates to more than one experiment;
- 'positive response' is equivalent to a 'yes' answer (indicated by 1 in the yes_answer column).
